const source = $input.first().json.body ?? $input.first().json;
const enabled = String($env.MEDIA_RABBITMQ_CANARY_ENABLED || 'false').trim().toLowerCase() === 'true';
const expectedToken = String($env.MEDIA_RABBITMQ_CANARY_TOKEN || '').trim();
const providedToken = String(source.canaryToken || '').trim();
const requestId = typeof source.requestId === 'string' && source.requestId.trim()
  ? source.requestId.trim()
  : `req-rabbitmq-canary-${Date.now()}`;

if (!enabled) {
  return [{ json: {
    route: 'blocked',
    responseCode: 423,
    requestId,
    ok: false,
    status: 'blocked',
    errorCode: 'RABBITMQ_CANARY_DISABLED',
    message: 'RabbitMQ canary workflow is staged but disabled. Set MEDIA_RABBITMQ_CANARY_ENABLED=true only after explicit approval.'
  } }];
}

if (!expectedToken || providedToken !== expectedToken) {
  return [{ json: {
    route: 'blocked',
    responseCode: 403,
    requestId,
    ok: false,
    status: 'blocked',
    errorCode: 'RABBITMQ_CANARY_UNAUTHORIZED',
    message: 'RabbitMQ canary token is missing or invalid.'
  } }];
}

if (source.confirm !== 'rabbitmq-canary-approved') {
  return [{ json: {
    route: 'blocked',
    responseCode: 400,
    requestId,
    ok: false,
    status: 'blocked',
    errorCode: 'RABBITMQ_CANARY_CONFIRMATION_REQUIRED',
    message: 'Set confirm to rabbitmq-canary-approved for a canary request.'
  } }];
}

const duration = 15;
const bpm = 90;
const seed = Number.isInteger(source.seed) ? source.seed : Date.now();
const tags = typeof source.tags === 'string' && source.tags.trim()
  ? source.tags.trim()
  : 'short cinematic electronic canary test, clean mix';
const lyrics = typeof source.lyrics === 'string' ? source.lyrics : '';
const language = typeof source.language === 'string' && source.language.trim() ? source.language.trim() : 'en';
const keyscale = typeof source.keyscale === 'string' && source.keyscale.trim() ? source.keyscale.trim() : 'C major';
const timesignature = typeof source.timesignature === 'string' && source.timesignature.trim() ? source.timesignature.trim() : '4';
const traceId = typeof source?.metadata?.traceId === 'string' && source.metadata.traceId
  ? source.metadata.traceId
  : `trace-${requestId}`;

const comfyWorkflow = {
  '97': { inputs: { ckpt_name: 'ace_step_1.5_turbo_aio.safetensors' }, class_type: 'CheckpointLoaderSimple', _meta: { title: 'Load Checkpoint' } },
  '94': { inputs: { tags, lyrics, seed, bpm, duration, timesignature, language, keyscale, generate_audio_codes: true, cfg_scale: 3, temperature: 0.75, top_p: 0.9, top_k: 0, min_p: 0, clip: ['97', 1] }, class_type: 'TextEncodeAceStepAudio1.5', _meta: { title: 'TextEncodeAceStepAudio1.5' } },
  '78': { inputs: { shift: 3, model: ['97', 0] }, class_type: 'ModelSamplingAuraFlow', _meta: { title: 'ModelSamplingAuraFlow' } },
  '18': { inputs: { samples: ['3', 0], vae: ['97', 2] }, class_type: 'VAEDecodeAudio', _meta: { title: 'VAE Decode Audio' } },
  '98': { inputs: { seconds: duration, batch_size: 1 }, class_type: 'EmptyAceStep1.5LatentAudio', _meta: { title: 'Empty Ace Step 1.5 Latent Audio' } },
  '3': { inputs: { seed, steps: 15, cfg: 3, sampler_name: 'euler', scheduler: 'simple', denoise: 1, model: ['78', 0], positive: ['94', 0], negative: ['47', 0], latent_image: ['98', 0] }, class_type: 'KSampler', _meta: { title: 'KSampler' } },
  '104': { inputs: { filename_prefix: 'audio/rabbitmq-canary', quality: 'V0', audio: ['18', 0] }, class_type: 'SaveAudioMP3', _meta: { title: 'Save Audio (MP3)' } },
  '47': { inputs: { conditioning: ['94', 0] }, class_type: 'ConditioningZeroOut', _meta: { title: 'ConditioningZeroOut' } }
};

return [{ json: {
  route: 'ready',
  responseCode: 202,
  requestId,
  ok: true,
  status: 'ready',
  canaryOnly: true,
  publishDisabled: false,
  dispatchMode: 'rabbitmq',
  profile: 'acestep_turbo',
  duration,
  count: 1,
  tags,
  lyrics,
  bpm,
  language,
  keyscale,
  timesignature,
  workflowFile: 'music/audio_ace_step_1_5_balanced.json',
  comfyWorkflow,
  metadata: { source: 'openclaw-rabbitmq-canary', traceId },
  message: 'RabbitMQ canary guard passed. A single canary message will be published if the workflow is explicitly activated and invoked.'
} }];

const item = $input.first().json;
const nowMs = Date.now();
const suffix = Math.random().toString(36).slice(2, 8);
const jobId = `job_rabbitmq_canary_${nowMs}_${suffix}`;
const messageId = `msg_rabbitmq_canary_${nowMs}_${suffix}`;
const acceptedAt = $now.toISO();
const rabbitmqMessage = {
  version: 1,
  messageId,
  requestId: item.requestId,
  jobId,
  profile: item.profile,
  payload: {
    workflow: item.comfyWorkflow,
    workflowFile: item.workflowFile,
    metadata: {
      ...(item.metadata || {}),
      canaryOnly: true,
      acceptedAt
    }
  }
};
return [{ json: {
  ...item,
  jobId,
  brokerMessageId: messageId,
  acceptedAt,
  rabbitmqExchange: 'media.jobs',
  rabbitmqRoutingKey: 'media.generate',
  rabbitmqMessage,
  route: 'publish'
} }];
